+using System.ComponentModel;
+using System.Net;
+using System.Text.RegularExpressions;
+
+namespace ResearchAgent.Tools;
+
+/// <summary>
+/// Provides web search and page fetching capabilities for the research agent.
+/// </summary>
+public sealed partial class WebSearchTool
+{
+    private readonly HttpClient _httpClient;
+
+    public WebSearchTool(HttpClient httpClient)
+    {
+        _httpClient = httpClient;
+    }
+
+    [Description("Search the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
+    public async Task<string> SearchWebAsync(
+        [Description("The search query to look up")] string query,
+        CancellationToken cancellationToken = default)
+    {
+        var encoded = Uri.EscapeDataString(query);
+        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
+
+        using var request = new HttpRequestMessage(HttpMethod.Get, url);
+        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
+
+        using var response = await _httpClient.SendAsync(request, cancellationToken);
+        response.EnsureSuccessStatusCode();
+
+        var html = await response.Content.ReadAsStringAsync(cancellationToken);
+        var results = ParseSearchResults(html);
+
+        return results.Count == 0
+            ? "No results found."
+            : string.Join("\n\n", results.Select((r, i) => $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
+    }
+
+    [Description("Fetch the text content of a web page at the given URL. Returns the first ~3000 characters of readable text.")]
+    public async Task<string> FetchPageAsync(
+        [Description("The full URL of the web page to fetch")] string url,
+        CancellationToken cancellationToken = default)
+    {
+        try
+        {
+            using var request = new HttpRequestMessage(HttpMethod.Get, url);
+            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
+
+            using var response = await _httpClient.SendAsync(request, cancellationToken);
+            response.EnsureSuccessStatusCode();
+
+            var html = await response.Content.ReadAsStringAsync(cancellationToken);
+            var text = ExtractReadableText(html);
+
+            const int maxLength = 3000;
+            if (text.Length > maxLength)
+                text = text[..maxLength] + "\n\n[...truncated]";
+
+            return string.IsNullOrWhiteSpace(text)
+                ? "Could not extract readable text from this page."
+                : text;
+        }
+        catch (HttpRequestException ex)
+        {
+            return $"Failed to fetch page: {ex.Message}";
+        }
+    }
+
+    private static List<SearchResult> ParseSearchResults(string html)
+    {
+        var results = new List<SearchResult>();
+        var matches = ResultBlockRegex().Matches(html);
+
+        foreach (Match match in matches)
+        {
+            if (results.Count >= 5)
+                break;
+
+            var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value).Trim();
+            var title = StripHtml(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();
+            var snippet = StripHtml(WebUtility.HtmlDecode(match.Groups["snippet"].Value)).Trim();
+
+            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
+            if (rawUrl.Contains("uddg="))
+            {
+                var uddgMatch = UddgRegex().Match(rawUrl);
+                if (uddgMatch.Success)
+                    rawUrl = Uri.UnescapeDataString(uddgMatch.Groups[1].Value);
+            }
+
+            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(rawUrl))
+                results.Add(new SearchResult(title, rawUrl, snippet));
+        }
+
+        return results;
+    }
