using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes. Use this to review what has been gathered before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
    }

    private sealed record Note(string Title, string Content, DateTime SavedAt);
}

