using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
var httpClient = new HttpClient();
var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetNotes),
};

// --- Build the agent with MAF ---
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic provided by the user.

    Follow this workflow:
    1. Search the web for the topic using multiple queries to get broad coverage.
    2. Fetch and read promising pages to gather detailed information.
    3. Save important findings as notes with descriptive titles.
    4. After gathering enough information, review your notes.
    5. Produce a well-structured summary with key findings, organized by theme.

    Be thorough but concise. Cite sources where possible. If the initial search
    doesn't yield good results, try rephrasing your queries.
    """;

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        Research Agent (MAF)          ║");
Console.WriteLine("║  Enter a topic to research, or      ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching... (the agent will search the web, take notes, and summarize)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var userMessage = new ChatMessage(ChatRole.User,
            $"{instructions}\n\nPlease research the following topic: {topic}");

        await foreach (var update in agent.RunStreamingAsync(userMessage, session))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("Goodbye!");
httpClient.Dispose();

